#include <unordered_map>
std::unordered_map<int,long long> memo;
long long fibonacci_memo(int n) {
    if (n <= 1) return n;
    if (memo.count(n)) return memo[n];
    return memo[n] = fibonacci_memo(n-1) + fibonacci_memo(n-2);
}

