fn fibonacci_memo(n: Int, memo: Dict[Int, Int]) -> Int:
    if n <= 1:
        return n
    if n in memo:
        return memo[n]
    var result = fibonacci_memo(n - 1, memo) + fibonacci_memo(n - 2, memo)
    memo[n] = result
    return result
